#if defined(_WIN32)
typedef HANDLE thread_t;
#define thread_create(t, fn, arg) (*t = CreateThread(NULL, 0, (LPTHREAD_START_ROUTINE)fn, arg, 0, NULL), *t != NULL)
#define thread_join(t) (WaitForSingleObject(t, INFINITE), CloseHandle(t))
#else
typedef pthread_t thread_t;
#define thread_create(t, fn, arg) (pthread_create(t, NULL, fn, arg) == 0)
#define thread_join(t) pthread_join(t)
#endif

#define NUM_CONTROLS 4500
#define NUM_TEST_CASES 1000
#define WAVE_GRID_SIZE 40
#define WAVE_COURANT 0.5f
#define WAVE_OMEGA 0.2f

typedef struct {
    uint32_t primary_synced;       // 1 = synced, 0 = desynced
    uint32_t replication_lag;      // lag in ms
    uint32_t sync_threshold;       // max allowed lag in ms
    uint32_t active_nodes;         // count of nodes online
    uint32_t consensus_quorum;     // 1 = quorum reached, 0 = no quorum
    uint32_t heartbeat_rtt_ms;     // RTT of heartbeats
    uint32_t term_id;              // raft/consensus term ID
    uint32_t election_timeout_ms;  // election timeout config
} cluster_status_t;

